// ═══════════════════════════════════════════════════════════════
// 07 · PARSEAR RESPUESTA DE OPENAI
// ═══════════════════════════════════════════════════════════════

const responseData = $input.first().json;

let claudeResponse;
try {
  // Extraer texto de la respuesta de Anthropic API
  const rawText = responseData.choices?.[0]?.message?.content ?? '';
  // Limpiar posibles bloques markdown que Claude agregue
  const cleanText = rawText
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/,   '')
    .trim();
  claudeResponse = JSON.parse(cleanText);
} catch(e) {
  // Fallback si el parseo falla — el bot pide que repitan el mensaje
  claudeResponse = {
    respuesta:         'Perdona, tuve un pequeño problema técnico 😅 ¿Puedes repetirme eso?',
    nuevo_estado:      'INICIO',
    pedido_actualizado: [],
    datos_cliente:     { nombre: '', hora_retiro: '' },
    pedido_confirmado: false,
    total_pedido:      0,
    accion_interna:    'ninguna',
    nota_interna:      'ERROR parseo Claude: ' + e.message
  };
}

// ─── Agregar respuesta del bot al historial ─────────────────────────
const historialActual = $('05 · Preparar Input Claude').all()[0]?.json?.historial_con_cliente || [];
historialActual.push({
  rol:   'bot',
  texto: claudeResponse.respuesta,
  ts:    new Date().toISOString()
});
// Mantener últimas 40 entradas (20 turnos) para no inflar Sheets
const historialFinal = historialActual.length > 40
  ? historialActual.slice(-40)
  : historialActual;

// ─── Sanitizar pedido_actualizado ──────────────────────────────────
const pedido = Array.isArray(claudeResponse.pedido_actualizado)
  ? claudeResponse.pedido_actualizado
  : [];

// ─── Calcular total si no viene de Claude ──────────────────────────
const total = claudeResponse.total_pedido ||
  pedido.reduce((acc, item) => acc + (item.precio || 0), 0);

return [{
  json: {
    ...claudeResponse,
    pedido_actualizado:   pedido,
    total_pedido:         total,
    historial_para_sheets: JSON.stringify(historialFinal),
    pedido_para_sheets:    JSON.stringify(pedido)
  }
}];

